    /// <summary>
    /// Lazy-initialized reverse lookup from TechPack Id (e.g. "^UP_JET4") to Class (e.g. "S").
    /// Uses the first occurrence found in the Dictionary. Returns null for unknown IDs.
    /// </summary>
    private static Dictionary<string, string>? _idToClass;
    /// <summary>Returns the class letter for a tech pack by its item ID, or null if not found.</summary>
    /// <param name="itemId">The item ID (with or without ^ prefix).</param>
    /// <returns>A class letter (e.g. "C", "B", "A", "S"), or null if unknown.</returns>
    public static string? GetClassById(string itemId)
    {
        if (_idToClass == null)
        {
            _idToClass = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            foreach (var tp in Dictionary.Values)
            {
                if (!string.IsNullOrEmpty(tp.Class) && tp.Class != "NONE" && tp.Class != "?"
                    && !_idToClass.ContainsKey(tp.Id))
                    _idToClass[tp.Id] = tp.Class;
            }
        }
        // Try exact match, then with/without ^ prefix
        if (_idToClass.TryGetValue(itemId, out var cls)) return cls;
        if (itemId.StartsWith("^") && _idToClass.TryGetValue(itemId[1..], out cls)) return cls;
        if (!itemId.StartsWith("^") && _idToClass.TryGetValue("^" + itemId, out cls)) return cls;
        return null;
    }
